#include<bits/stdc++.h>
using namespace std;
struct edge
{
    long long to,val,nxt;
}e[200010],e1[200010];
long long head[200010],tot=1,a[200010],f[200010];
long long n,m,s,t,d[200010],now[200010];
void add1(long long u,long long v,long long w)
{
    e[++tot]=(edge){v,w,head[u]};
    head[u]=tot;
}
void add(long long u,long long v,long long w)
{
    add1(u,v,w);
    add1(v,u,0);
}
bool bfs()
{
    for(long long i=0;i<=t;i++)
    {
        d[i]=0;
    }
    d[s]=1;
    queue<long long> q;
    q.push(s);
    while(!q.empty())
    {
        long long t=q.front();
        q.pop();
        for(long long i=head[t];i;i=e[i].nxt)
        {
            long long v=e[i].to,val=e[i].val;
            if(d[v]==0&&val)
            {
                d[v]=d[t]+1;
                q.push(v);
                if(v==::t)
                {
                    return true;
                }
            }
        }
    }
    return false;
}
long long dfs(long long x,long long flow)
{
    if(x==t||flow==0)
    {
        return flow;
    }
    long long sum=0;
    for(long long i=now[x];i;i=e[i].nxt)
    {
        now[x]=i;
        long long v=e[i].to,val=e[i].val;
        if(d[v]==d[x]+1&&val)
        {
            long long tmp=dfs(v,min(flow,val));
            e[i].val-=tmp;
            e[i^1].val+=tmp;
            sum+=tmp;
            flow-=tmp;
            if(flow==0)
            {
                break;
            }
        }
    }
    if(sum==0)
    {
        d[x]=0;
    }
    return sum;
}
long long dinic()
{
    long long ans=0;
    while(bfs())
    {
        for(long long i=0;i<=t;i++)
        {
            now[i]=head[i];
        }
        ans+=dfs(s,2e9);
    }
    return ans;
}
int main()
{
    scanf("%lld",&n);
    if(n==1)
    {
        printf("1\n1\n1\n");
        return 0;
    }
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
    }
    long long len=0;
    for(long long i=1;i<=n;i++)
    {
        f[i]=1;
        for(long long j=1;j<i;j++)
        {
            if(a[j]<=a[i])
            {
                f[i]=max(f[i],f[j]+1);
            }
        }
        len=max(len,f[i]);
    }
    printf("%lld\n",len);
    s=n*2+1;
    t=n*2+2;
    for(long long i=1;i<=n;i++)
    {
        for(long long j=1;j<i;j++)
        {
            if(a[j]<=a[i]&&f[i]==f[j]+1)
            {
                add(j*2,i*2-1,1);
            }
        }
    }
    for(long long i=1;i<=n;i++)
    {
        if(f[i]==1)
        {
            add(s,i*2-1,1);
        }
        if(f[i]==len)
        {
            add(i*2,t,1);
        }
        add(i*2-1,i*2,1);
    }
    memcpy(e1,e,sizeof(e));
    printf("%lld\n",dinic());
    memcpy(e,e1,sizeof(e));
    add(s,1,2e9);
    add(1,2,2e9);
    if(f[n]==len)
    {
        add(n*2-1,n*2,2e9);
        add(n*2,t,2e9);
    }
    printf("%lld\n",dinic());
    return 0;
}
